(function () {
  const greek = {
    alpha: "α", beta: "β", gamma: "γ", delta: "δ", epsilon: "ε",
    theta: "θ", lambda: "λ", mu: "μ", pi: "π", rho: "ρ",
    sigma: "σ", phi: "φ", varphi: "φ", omega: "ω",
    Delta: "Δ", Omega: "Ω"
  };

  function escapeHtml(value) {
    return String(value)
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;")
      .replace(/'/g, "&#39;");
  }

  function replaceCommandGroup(input, command, renderer) {
    let output = "";
    let index = 0;
    const token = "\\" + command + "{";
    while (index < input.length) {
      const start = input.indexOf(token, index);
      if (start < 0) {
        output += input.slice(index);
        break;
      }
      output += input.slice(index, start);
      let depth = 1;
      let cursor = start + token.length;
      const bodyStart = cursor;
      while (cursor < input.length && depth > 0) {
        const ch = input[cursor];
        if (ch === "{") depth += 1;
        if (ch === "}") depth -= 1;
        cursor += 1;
      }
      if (depth !== 0) {
        output += input.slice(start, cursor);
        index = cursor;
        continue;
      }
      output += renderer(input.slice(bodyStart, cursor - 1));
      index = cursor;
    }
    return output;
  }

  function replaceFrac(input) {
    let output = "";
    let index = 0;
    const token = "\\frac{";
    while (index < input.length) {
      const start = input.indexOf(token, index);
      if (start < 0) {
        output += input.slice(index);
        break;
      }
      output += input.slice(index, start);
      let cursor = start + token.length;
      let depth = 1;
      const numStart = cursor;
      while (cursor < input.length && depth > 0) {
        if (input[cursor] === "{") depth += 1;
        if (input[cursor] === "}") depth -= 1;
        cursor += 1;
      }
      if (depth !== 0 || input[cursor] !== "{") {
        output += input.slice(start, cursor);
        index = cursor;
        continue;
      }
      const numerator = input.slice(numStart, cursor - 1);
      cursor += 1;
      depth = 1;
      const denStart = cursor;
      while (cursor < input.length && depth > 0) {
        if (input[cursor] === "{") depth += 1;
        if (input[cursor] === "}") depth -= 1;
        cursor += 1;
      }
      if (depth !== 0) {
        output += input.slice(start, cursor);
        index = cursor;
        continue;
      }
      output += '<span class="math-frac"><span class="num">' + renderMath(numerator) + '</span><span class="den">' + renderMath(input.slice(denStart, cursor - 1)) + '</span></span>';
      index = cursor;
    }
    return output;
  }

  function replaceScripts(input) {
    return input
      .replace(/([A-Za-z0-9)\]}])\^\{([^{}]+)\}/g, "$1<sup>$2</sup>")
      .replace(/([A-Za-z0-9)\]}])_\{([^{}]+)\}/g, "$1<sub>$2</sub>")
      .replace(/([A-Za-z0-9)\]}])\^([A-Za-z0-9+\-]+)/g, "$1<sup>$2</sup>")
      .replace(/([A-Za-z0-9)\]}])_([A-Za-z0-9+\-]+)/g, "$1<sub>$2</sub>");
  }

  function renderMath(value) {
    let html = escapeHtml(value);
    html = replaceFrac(html);
    html = replaceCommandGroup(html, "sqrt", body => '<span class="math-sqrt">√<span class="radicand">' + renderMath(body) + '</span></span>');
    html = html.replace(/\\text\{([^{}]*)\}/g, "$1");
    html = html.replace(/\\([A-Za-z]+)/g, function (_, name) {
      if (greek[name]) return greek[name];
      if (name === "times") return "×";
      if (name === "cdot") return "·";
      if (name === "approx") return "≈";
      if (name === "sum") return "∑";
      if (name === "cos") return "cos";
      if (name === "tan") return "tan";
      if (name === "sin") return "sin";
      if (name === "Omega") return "Ω";
      if (name === "circ") return "°";
      return name;
    });
    return replaceScripts(html);
  }

  function renderMixedText(value) {
    const text = String(value || "");
    let html = "";
    let i = 0;
    while (i < text.length) {
      const blockStart = text.indexOf("$$", i);
      const inlineStart = text.indexOf("$", i);
      let start = -1;
      let block = false;
      if (blockStart >= 0 && (inlineStart < 0 || blockStart <= inlineStart)) {
        start = blockStart;
        block = true;
      } else if (inlineStart >= 0) {
        start = inlineStart;
      }
      if (start < 0) {
        html += escapeHtml(text.slice(i));
        break;
      }
      html += escapeHtml(text.slice(i, start));
      const delimiter = block ? "$$" : "$";
      const contentStart = start + delimiter.length;
      const end = text.indexOf(delimiter, contentStart);
      if (end < 0) {
        html += escapeHtml(text.slice(start));
        break;
      }
      const className = block ? "formula-block" : "formula-inline";
      html += '<span class="' + className + '">' + renderMath(text.slice(contentStart, end)) + '</span>';
      i = end + delimiter.length;
    }
    html = html.replace(/\n/g, "<br>");
    return html;
  }

  function measureHeight(root) {
    const rect = root.getBoundingClientRect();
    return Math.ceil(Math.max(
      rect.height,
      root.scrollHeight,
      document.body.scrollHeight,
      document.documentElement.scrollHeight
    ));
  }

  function notifyHeight(root) {
    if (window.AndroidRichText && window.AndroidRichText.onHeightChanged) {
      window.AndroidRichText.onHeightChanged(measureHeight(root));
    }
  }

  window.renderRichText = function (value) {
    const root = document.getElementById("content");
    root.innerHTML = renderMixedText(value);
    requestAnimationFrame(function () { notifyHeight(root); });
    setTimeout(function () { notifyHeight(root); }, 30);
    setTimeout(function () { notifyHeight(root); }, 120);
  };
})();
